import React from 'react';
import { useLocation, Link } from 'react-router-dom';
import './BookingSuccess.css';

function BookingSuccess() {
  const { state } = useLocation();
  const { bookingData, eventData, total } = state || {};

  const bookingId = `MVB-${Date.now().toString().slice(-8)}`;

  const formattedDate = eventData
    ? new Date(eventData.date).toLocaleDateString('en-IN', {
        weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
      })
    : '';

  if (!bookingData) {
    return (
      <div className="container" style={{ padding: '80px 24px', textAlign: 'center' }}>
        <h2>No booking data found</h2>
        <Link to="/events" className="btn-primary" style={{ marginTop: '20px' }}>Browse Events</Link>
      </div>
    );
  }

  return (
    <div className="success-page">
      <div className="container">
        <div className="success-card">
          {/* Icon */}
          <div className="success-card__icon">✓</div>
          <h1>Booking Confirmed!</h1>
          <p className="success-card__sub">
            Thank you, <strong>{bookingData.name}</strong>! Your booking has been confirmed and a confirmation email has been sent to <strong>{bookingData.email}</strong>.
          </p>

          {/* Booking reference */}
          <div className="success-card__ref">
            <span>Booking Reference</span>
            <span className="success-card__ref-id">{bookingId}</span>
          </div>

          {/* Event summary */}
          <div className="success-card__summary">
            <div className="success-card__row">
              <span>Event</span>
              <span>{eventData?.title}</span>
            </div>
            <div className="success-card__row">
              <span>Date & Time</span>
              <span>{formattedDate} · {eventData?.time}</span>
            </div>
            <div className="success-card__row">
              <span>Venue</span>
              <span>{eventData?.location}</span>
            </div>
            <div className="success-card__row">
              <span>Tickets</span>
              <span>{bookingData.tickets} ticket{bookingData.tickets > 1 ? 's' : ''}</span>
            </div>
            <div className="success-card__row success-card__row--total">
              <span>Total Paid</span>
              <span>₹{total?.toLocaleString('en-IN')}</span>
            </div>
          </div>

          <div className="success-card__notice">
            <p>📧 A detailed confirmation has been emailed to <strong>{bookingData.email}</strong>.</p>
            <p>Our team has also been notified of your booking.</p>
          </div>

          <div className="success-card__actions">
            <Link to="/events" className="btn-primary">Browse More Events</Link>
            <Link to="/" className="btn-outline">Back to Home</Link>
          </div>
        </div>
      </div>
    </div>
  );
}

export default BookingSuccess;
